import{_ as o,o as t,c as r,a2 as a}from"./chunks/framework.CKCxdkvf.js";const s="/orrery/docs/assets/locale-es.DywPr3p6.png",i="/orrery/docs/assets/01-explore.16jnAKd0.png",n="/orrery/docs/assets/02-plan.uYSxfkHD.png",l="/orrery/docs/assets/03-fly-curiosity.CyezK__M.png",c="/orrery/docs/assets/03-fly-apollo11.BCmkI-2l.png",h="/orrery/docs/assets/04-missions.k4ugMK_M.png",p="/orrery/docs/assets/mission-panel.Uiq4Bfki.png",d="/orrery/docs/assets/05-earth.C8N3AZHo.png",g="/orrery/docs/assets/06-moon.BFvZZ_8K.png",v=JSON.parse('{"title":"User Guide","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide.md","filePath":"user-guide.md"}'),u={name:"user-guide.md"};function m(y,e,f,b,k,w){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="user-guide" tabindex="-1">User Guide <a class="header-anchor" href="#user-guide" aria-label="Permalink to &quot;User Guide&quot;">​</a></h1><p><em>Orrery — read-this-first guide for the live app · v0.3.x · May 2026</em></p><blockquote><p>Every screenshot in this guide comes from the production app. Click any image to open it full-size in a new tab.</p></blockquote><hr><h2 id="switching-language" tabindex="-1">Switching language <a class="header-anchor" href="#switching-language" aria-label="Permalink to &quot;Switching language&quot;">​</a></h2><p>A locale picker sits in the top-right of the navigation bar. Click the chip (<code>EN</code> / <code>ES</code>) to open the dropdown, pick your language, and the URL updates to <code>?lang=&lt;code&gt;</code>. Bookmark the URL to lock your locale; share it and your reader gets the same.</p><p>There is no <code>localStorage</code> and no cookie — the URL is the only place your locale lives. On a fresh visit the browser language is sniffed (<code>navigator.language</code>) and applied automatically; if it doesn&#39;t match a supported locale, English is the default.</p><p><a href="screenshots/locale-es.png"><img src="'+s+'" alt="Spanish locale"></a></p><p>Currently shipped: <strong>English</strong> and <strong>Spanish</strong>. The roadmap (per <a href="./adr/ADR-031">ADR-031</a>): Mandarin, French, Japanese, German, Hindi, Portuguese-BR, Arabic (RTL), Korean, Russian, Italian.</p><hr><h2 id="solar-system-explorer-·-explore" tabindex="-1">Solar System Explorer · <code>/explore</code> <a class="header-anchor" href="#solar-system-explorer-·-explore" aria-label="Permalink to &quot;Solar System Explorer · `/explore`&quot;">​</a></h2><p>A real-time 3D / 2D orrery showing 8 planets, 5 dwarf planets, 2 comets, and ʻOumuamua (the only confirmed interstellar object).</p><p><a href="screenshots/01-explore.png"><img src="'+i+'" alt="Explorer screenshot"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Drag</strong> the 3D scene to orbit around the Sun.</li><li><strong>Scroll</strong> / <strong>pinch</strong> to zoom.</li><li><strong>Click any body</strong> — Sun, planet, dwarf, comet, ʻOumuamua — to open its detail panel with OVERVIEW · GALLERY · TECHNICAL · REFERENCES · LEARN tabs.</li><li><strong>Hover</strong> in 3D for a velocity tooltip (mean orbital velocity via vis-viva).</li><li><strong><code>2D</code> toggle</strong> (top right) — switches to a top-down 2D plot of the ecliptic plane.</li><li><strong><code>REFERENCES</code> toggle</strong> — opens a true-relative-size diorama of the planets.</li><li><strong><code>LAYERS</code> toggle</strong> — show / hide PLANETS · DWARFS · COMETS · INTERSTELLAR independently. Hidden bodies aren&#39;t clickable.</li></ul><hr><h2 id="mission-configurator-·-plan" tabindex="-1">Mission Configurator · <code>/plan</code> <a class="header-anchor" href="#mission-configurator-·-plan" aria-label="Permalink to &quot;Mission Configurator · `/plan`&quot;">​</a></h2><p>The Lambert porkchop plot. Pick a destination + mission type (LANDING or FLYBY). Each destination uses a <strong>pre-computed</strong> 112×100 grid (11,200 cells) checked in at <code>static/data/porkchop/</code> and loaded by the app at runtime — the Lambert <strong>Web Worker</strong> stays in the bundle for future custom-range work but is <strong>not</strong> what paints the default Mercury–Saturn maps. Cool teal cells are cheap launch windows; red cells are expensive.</p><p><a href="screenshots/02-plan.png"><img src="'+n+'" alt="Porkchop screenshot"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Click any cell</strong> to read the exact dep / arr dates, transit, and ∆v.</li><li><strong>Pick a vehicle</strong> from 13 launch rockets — the panel computes vehicle ∆v vs required ∆v and shows margin or deficit.</li><li><strong>▶ FLY MISSION</strong> — opens <code>/fly</code> with your selected dep / arr / vehicle baked into the URL.</li><li><strong>Mobile</strong>: long-press the porkchop for a magnifier loupe.</li></ul><hr><h2 id="mission-arc-·-fly" tabindex="-1">Mission Arc · <code>/fly</code> <a class="header-anchor" href="#mission-arc-·-fly" aria-label="Permalink to &quot;Mission Arc · `/fly`&quot;">​</a></h2><p>The mission visualisation. Earth, the destination, and the spacecraft animate live; the trajectory tube uses a true two-point Keplerian ellipse with Sun at focus, so both endpoints lock to live planet positions.</p><p><a href="screenshots/03-fly-curiosity.png"><img src="'+l+'" alt="Curiosity flight"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Scrub the timeline</strong> — bottom bar — to fly the mission from launch to arrival.</li><li><strong>▶ / ⏸ + speed pills</strong> — autoplay at 1× / 7× / 30× / 90× (Mars-class missions) or 0.1× / 0.5× / 1× / 3× (lunar).</li><li><strong><code>2D</code> toggle</strong> — switch between the 3D scene and a top-down 2D view.</li><li><strong>CAPCOM panel</strong> (right) — live mission events (TLI, TCM, EDL, etc.) tick by as you scrub.</li><li><strong>Pre-built missions</strong>: try <code>/fly?mission=&lt;id&gt;</code> for any of the 36 missions in the library.</li><li><strong>Lunar missions</strong> (Apollo, Artemis II, Blue Moon, Chang&#39;e, Chandrayaan, Luna, SLIM) render heliocentrically with the Earth + Moon system orbiting the Sun, and the Moon orbiting Earth at an exaggerated visual distance so the cislunar trajectory is visible.</li></ul><p><a href="screenshots/03-fly-apollo11.png"><img src="'+c+'" alt="Apollo 11 fly"></a></p><hr><h2 id="mission-library-·-missions" tabindex="-1">Mission Library · <code>/missions</code> <a class="header-anchor" href="#mission-library-·-missions" aria-label="Permalink to &quot;Mission Library · `/missions`&quot;">​</a></h2><p>All 36 missions in the dataset. 16 Mars + 16 Moon + 4 outer-system entries (Galileo, Voyager 2, New Horizons, Dawn), spanning Mariner 4 (1964) through Starship Mars Crew (concept).</p><p><a href="screenshots/04-missions.png"><img src="'+h+'" alt="Library"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Filter</strong> by destination / agency / status.</li><li><strong>Timeline navigator</strong> — scrub the year window (1957 → 2030) to narrow the set.</li><li><strong>Click any card</strong> — opens a detail panel with OVERVIEW · FLIGHT · GALLERY · LEARN tabs.</li><li><strong>▶ FLY</strong> from any panel — jumps to <code>/fly?mission=&lt;id&gt;</code>.</li></ul><p><a href="screenshots/mission-panel.png"><img src="'+p+'" alt="Mission detail"></a></p><hr><h2 id="earth-orbit-·-earth" tabindex="-1">Earth Orbit · <code>/earth</code> <a class="header-anchor" href="#earth-orbit-·-earth" aria-label="Permalink to &quot;Earth Orbit · `/earth`&quot;">​</a></h2><p>Logarithmic radial scale showing the infrastructure that surrounds Earth: ISS, Tiangong, Hubble, JWST, Gaia, Chandra, XMM-Newton, LRO + the four GNSS constellations (GPS, Galileo, GLONASS, BeiDou) + GEO ring.</p><p><a href="screenshots/05-earth.png"><img src="'+d+'" alt="Earth orbit"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>3D toggle</strong> — drag to orbit Earth; objects sit at their real inclinations.</li><li><strong>2D toggle</strong> — top-down view with logarithmic radial spacing. ISS sits at one ring, GEO at another, JWST near the L2 marker.</li><li><strong>Click any object</strong> — detail panel with launch / period / inclination / crew / capability fields.</li><li><strong>Year scrubber</strong> — see what was in orbit in 1990, 2010, 2025, etc.</li></ul><hr><h2 id="moon-map-·-moon" tabindex="-1">Moon Map · <code>/moon</code> <a class="header-anchor" href="#moon-map-·-moon" aria-label="Permalink to &quot;Moon Map · `/moon`&quot;">​</a></h2><p>16 lunar landing sites across 5 nations, plotted by latitude / longitude on a 3D Moon globe and a 2D equirectangular projection.</p><p><a href="screenshots/06-moon.png"><img src="'+g+'" alt="Moon map"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>3D Moon</strong> — drag to rotate, click any marker for site detail.</li><li><strong>2D map</strong> — equirectangular projection; click any marker for the same panel.</li><li><strong>Site panel</strong> — OVERVIEW · GALLERY · LEARN, plus mission-specific fields (crew, surface time, samples returned, capability unlocked).</li></ul><hr><h2 id="mobile" tabindex="-1">Mobile <a class="header-anchor" href="#mobile" aria-label="Permalink to &quot;Mobile&quot;">​</a></h2><p>Every screen works at 375 px width. Touch targets are 44×44 px minimum. Bottom-sheet panels swipe down to dismiss. The porkchop magnifier loupe is mobile-only (long-press on the plot).</p><p>The PWA manifest is shipped — install Orrery as a standalone app via the browser menu (Chrome / Safari / Firefox all support this; the in-app install nag is intentionally suppressed per <a href="./adr/ADR-029">ADR-029</a>).</p><hr><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><ul><li>No analytics.</li><li>No tracking.</li><li>No cookies.</li><li>No <code>localStorage</code>.</li><li>No third-party fonts, images, or scripts loaded at runtime — every asset is bundled at build time per <a href="./adr/ADR-016">ADR-016</a>.</li></ul><p>The only state that persists across sessions is what&#39;s in the URL (<code>?lang=</code>, <code>?mission=</code>, <code>?dest=</code>, etc.) and the service-worker cache (so the app works offline after the first load).</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>The 3D scene is empty.</strong> Most likely WebGL is disabled in your browser. Try a different browser or enable WebGL.</p><p><strong>Images don&#39;t load.</strong> Either you&#39;re offline before the service worker has cached them, or NASA Images API is rate-limiting. Reload after a minute; cached images persist.</p><p><strong>A translation looks weird.</strong> Spanish is the only non-English locale today, translated LLM-only with a physics-terminology glossary (per <a href="./adr/ADR-033">ADR-033</a>). File an issue if a term is wrong; the glossary is the binding source of truth.</p><p><strong>Missions render outside the camera.</strong> For lunar missions the camera is tight on Earth + Moon (Sun off-camera by design — see <a href="./adr/ADR-031">ADR-031</a> Wave 1 scope). Drag to pan; scroll to zoom.</p><hr><h2 id="where-to-next" tabindex="-1">Where to next <a class="header-anchor" href="#where-to-next" aria-label="Permalink to &quot;Where to next&quot;">​</a></h2><ul><li><strong><a href="./concept/02_Project_Concept">02 Project Concept</a></strong> — the complete synthesis of what Orrery is.</li><li><strong><a href="./concept/03_Data_Catalog">03 Data Catalog</a></strong> — every constant, every source, mission schema, credit format.</li><li><strong><a href="./i18n-style-guide">i18n style guide</a></strong> — the binding glossary for translators.</li><li><strong><code>CLAUDE.md</code></strong> in the repo root — engineering constraints if you&#39;re contributing code (visible on GitHub: <a href="https://github.com/chipi/orrery/blob/main/CLAUDE.md" target="_blank" rel="noreferrer">https://github.com/chipi/orrery/blob/main/CLAUDE.md</a>).</li></ul>',64)])])}const S=o(u,[["render",m]]);export{v as __pageData,S as default};
